<?php
namespace App\Services\KepalaDinas;
use App\Models\{AuditLog,ExportLog,KbliReference,MonitoringPeriod,RegionReference,Umkm,UmkmLegality,UmkmPerformanceRecord};
class StrategicDashboardService { public function indicators(): array { return ['total_umkm'=>Umkm::query()->count(),'legalitas_terisi'=>UmkmLegality::query()->whereNotNull('nib_number')->count(),'kbli_aktif'=>KbliReference::query()->where('is_active',true)->count(),'wilayah_aktif'=>RegionReference::query()->where('is_active',true)->count(),'periode_monitoring'=>MonitoringPeriod::query()->count(),'rekam_kinerja'=>UmkmPerformanceRecord::query()->count()]; } public function aggregateMapPoints(): array { return Umkm::query()->selectRaw('status_data, COUNT(*) as total')->groupBy('status_data')->pluck('total','status_data')->toArray(); } public function latestAuditSummary(): array { return AuditLog::query()->latest()->limit(20)->get(['action','target_type','event_time'])->toArray(); } public function recordExport(int $actorId, string $reason): void { ExportLog::query()->create(['actor_user_id'=>$actorId,'export_type'=>'kepala_dinas_ringkasan','export_reason'=>$reason,'watermark_token'=>sha1($actorId.'|'.$reason.'|'.now()->toIso8601String()),'status'=>'requested','exported_at'=>now()]); }}
